CREATE TABLE public.transaction_history (
    id integer NOT NULL,
    transaction_name character varying(100) NOT NULL,
    transaction_no character varying(20) NOT NULL,
    resident_id integer,
    rfid_uid character varying(50),
    status character varying(20) NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    transaction_type character varying(20) DEFAULT 'document'::character varying NOT NULL,
    CONSTRAINT ck_transaction_history_transaction_type CHECK (((transaction_type)::text = ANY ((ARRAY['document'::character varying, 'equipment'::character varying, 'rfid'::character varying])::text[])))
);


ALTER TABLE public.transaction_history OWNER TO admin;

--
-- Name: transaction_history_id_seq; Type: SEQUENCE; Schema: public; Owner: admin
--

CREATE SEQUENCE public.transaction_history_id_seq
    AS integer
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;


ALTER SEQUENCE public.transaction_history_id_seq OWNER TO admin;

--
-- Name: transaction_history_id_seq; Type: SEQUENCE OWNED BY; Schema: public; Owner: admin
--

ALTER SEQUENCE public.transaction_history_id_seq OWNED BY public.transaction_history.id;


